const payload = $input.first().json;
const userInfo = payload.user_id ? `User ID: ${payload.user_id}` : 'User ID: unknown';
const amountInfo = payload.amount ? `Amount: ${payload.amount} (minor units)` : '';

return [{
  json: {
    subject: `[ALERT] Payment error via ${payload.provider}: ${payload.error_code}`,
    body: `A payment processing error occurred.\nProvider: ${payload.provider}\nError: ${payload.error_code}\n${userInfo}\n${amountInfo}\nTrace ID: ${payload.trace_id || 'n/a'}\n\nCheck the payment logs and verify the user's balance was not affected.`,
    provider: payload.provider,
    error_code: payload.error_code,
    user_id: payload.user_id,
    amount: payload.amount,
    trace_id: payload.trace_id
  }
}];
